<script setup lang="ts">import type { Agent,Message } from '../domain/types';import MarkdownContent from './MarkdownContent.vue';import NpcAvatar from './NpcAvatar.vue';defineProps<{messages:readonly Message[];agents:readonly Agent[];activeAgentId?:number|null}>();const fallback=(m:Message):Agent=>({id:m.senderId,teamId:0,name:m.senderName||'来客',i18n:{},status:'idle'});</script>
<template><ol class="dialogue" aria-label="讨论内容"><li v-if="!messages.length" class="empty-state">房内尚无对话，静候第一声传讯。</li><li v-for="m in messages" :key="m.id??`${m.senderId}-${m.sentAt}`" :class="{operator:m.senderId<0}"><NpcAvatar :agent="agents.find(a=>a.id===m.senderId)||fallback(m)" :status="m.senderId===activeAgentId?'speaking':'idle'" compact/><article><header><b>{{m.senderName||agents.find(a=>a.id===m.senderId)?.name||'来客'}}</b><time>{{m.sentAt ? new Date(m.sentAt).toLocaleString('zh-CN',{hour:'2-digit',minute:'2-digit'}) : ''}}</time><span v-if="m.immediate">急件</span></header><MarkdownContent :content="m.content"/></article></li></ol></template>
